/**
 * FIFA World Cup years where the player was in the squad but did not play (0 minutes).
 * Those tournaments are omitted from level tiles and from per-year question buckets.
 * Prefer listing only years they actually played in `playerWorldCupYears` when known;
 * use this map when the roster row still lists a squad-only tournament for reference.
 */
export const playerWorldCupSquadOnlyYears: Record<string, number[]> = {};

function getMergedRawPlayerWorldCupYearsSorted(playerId: string): number[] {
  const primary = playerWorldCupYears[playerId];
  if (primary && primary.length > 0) return [...primary].sort((a, b) => a - b);
  const missing = missingPlayerWorldCupYears[playerId];
  if (missing && missing.length > 0) return [...missing].sort((a, b) => a - b);
  return [];
}

/** FIFA World Cup finals years for this legend (merged primary + missing), oldest first — squad-only years removed. */
export function getPlayerWorldCupYearsSorted(playerId: string): number[] {
  const raw = getMergedRawPlayerWorldCupYearsSorted(playerId);
  const exclude = playerWorldCupSquadOnlyYears[playerId];
  if (!exclude?.length) return raw;
  const ex = new Set(exclude);
  return raw.filter((y) => !ex.has(y));
}

/**
 * Years used for level tiles / tournament buckets: played finals plus `playerWorldCupSquadOnlyYears`
 * (unused sub / zero minutes) so verbatim fact-check campaigns still get a dedicated level.
 */
export function getPlayerWorldCupYearsForLevelsSorted(playerId: string): number[] {
  const played = getPlayerWorldCupYearsSorted(playerId);
  const squadOnly = playerWorldCupSquadOnlyYears[playerId];
  if (!squadOnly?.length) return played;
  return [...new Set([...played, ...squadOnly])].sort((a, b) => a - b);
}

/** Concatenate legend block records; later blocks only add questions whose `id` is new (no duplicate IDs). */
function mergeLegendQuestionBlocksByPlayerId(
  ...parts: Record<string, Question[]>[]
): Record<string, Question[]> {
  const out: Record<string, Question[]> = {};
  for (const part of parts) {
    for (const [pid, qs] of Object.entries(part)) {
      if (!out[pid]) out[pid] = [];
      const seen = new Set(out[pid].map((q) => q.id));
      for (const q of qs) {
        if (!seen.has(q.id)) {
          seen.add(q.id);
          out[pid].push(q);
        }
      }
    }
  }
  return out;
}

