/** Drops auto-generated “supplemental” spam, generic confederation geography, and pad-script trivia. */
function stripPlayerQuestionNoise(questions: Question[]): Question[] {
  return questions.filter((q) => {
    const t = q.question.trim();
    const tl = t.toLowerCase();
    if (/^supplemental\s+\d+:/i.test(t)) return false;
    if (/confederation region at the world cup/i.test(tl)) return false;
    if (/most closely associated with which confederation/i.test(tl)) return false;
    if (/^fact check\s*\(/i.test(t)) return false;
    if (/^trivia\s*\(/i.test(t)) return false;
    if (/fifa world cup finals tournament in \d{4} were hosted by which country/i.test(t)) return false;
    // Trivial with level header: same year is shown as “1994 🇺🇸” on the quiz card.
    if (
      /\b(in which year|in which calendar year)\b/i.test(tl) &&
      /\b(first appear|last play) at a fifa world cup finals tournament\b/i.test(tl)
    ) {
      return false;
    }
    if (
      /\bin which year\b/i.test(tl) &&
      /\bplay at (his|her) only fifa world cup finals tournament\b/i.test(tl)
    ) {
      return false;
    }
    if (
      /\bbetween\s+(19\d{2}|20\d{2})\s+and\s+(19\d{2}|20\d{2})\s*,\s*which calendar year marks\b/i.test(tl)
    ) {
      return false;
    }
    // Squad selection / eligibility padding — prefer on-pitch facts (goals, assists, cards, subs, time on pitch).
    if (/\b(listed in|named in).{0,100}(squad|finals squad|fifa world cup finals squad)\b/i.test(tl)) return false;
    if (/\bfifa world cup finals squad\b/i.test(tl)) return false;
    if (/\b(earn caps at|represent .{0,80} at the finals)\b/i.test(tl)) return false;
    if (/\bwhich national team did\b/i.test(tl)) return false;
    if (/\bwas named in\b.{0,120}\bsquad for\b/i.test(tl)) return false;
    // Drop club-padding unless the card is era-tagged (verbatim legend tiles); otherwise the pool
    // can fall below 10 per tournament and ten-grid padding clones an early stem — parentheticals
    // are stripped in the UI, so players see a duplicate question.
    if (/\bwhich english club\b/i.test(tl) && q.eventYear == null) return false;
    if (/\b(compete wearing|travelling and preparing|national team kit at the finals)\b/i.test(tl)) return false;
    if (/\bwhich confederation did\b/i.test(tl) && /\brepresent\b/i.test(tl)) return false;
    if (/\bshould have\b.+\b(scored|won|started)\b/i.test(tl)) return false;
    if (/\bvideo assistant referee\b/i.test(tl) || (/\bVAR\b/i.test(tl) && /\breview\b/i.test(tl))) return false;
    if (/\bcontroversial refereeing\b/i.test(tl)) return false;
    if (/\bcould extra time be played\b/i.test(tl)) return false;
    if (/\bgolden goal\b/i.test(tl) && /\bknockout\b/i.test(tl)) return false;
    return true;
  });
}

/** Totals must be 10, 20, 30, 40, or 50 so each level can be a multiple of 10 questions. */
function normalizePlayerPoolToTenGrid(
  pool: Question[],
  playerId: string,
  meta: PlayerQuizMeta | null,
): Question[] {
  if (pool.length === 0) return pool;
  let out = pool.length > 50 ? pool.slice(0, 50) : [...pool];
  if (out.length % 10 === 0) return out;
  // Pad pools in the 1–9 range up to 10 by cycling distinct prompts so each legend has a minimum playable set.
  if (out.length > 0 && out.length < 10) {
    const targetMin = 10;
    let i = 0;
    const baseMin = [...out];
    while (out.length < targetMin && i < 500) {
      const q = baseMin[i % baseMin.length];
      const n = out.length + 1;
      out.push({
        ...q,
        id: `${playerId}-min10-${n}-${i}`,
        question: `${q.question} (Card ${n})`,
      });
      i++;
    }
    if (out.length % 10 === 0) return out;
  }
  const target = Math.min(50, Math.ceil(out.length / 10) * 10);
  if (meta) {
    let guard = 0;
    while (out.length < target && guard < 30) {
      const extra = buildExtraQuestions(meta, out);
      const merged = dedupeLegendPlayerQuestions([...out, ...extra]);
      const cleaned = filterOffTopicPlayerQuestions(merged, playerId);
      if (cleaned.length <= out.length) break;
      out = cleaned.length > 50 ? cleaned.slice(0, 50) : cleaned;
      if (out.length % 10 === 0) return out;
      guard++;
    }
  }
  if (out.length > target) return out.slice(0, target);
  if (out.length < target && out.length > 0) {
    let i = 0;
    const base = [...out];
    while (out.length < target && i < 500) {
      const q = base[i % base.length];
      const n = out.length + 1;
      out.push({
        ...q,
        id: `${playerId}-tengrid-${n}-${i}`,
        question: `${q.question} (Card ${n})`,
      });
      i++;
    }
    return out.slice(0, target);
  }
  return out;
}

/** Drops prompts tied to a tournament year the player did not actually play in (squad-only years). */
function filterPlayerQuestionsToPlayedWorldCupYears(playerId: string, qs: Question[]): Question[] {
  const played = new Set(getPlayerWorldCupYearsSorted(playerId));
  const raw = getMergedRawPlayerWorldCupYearsSorted(playerId);
  const rawSet = new Set(raw);
  if (played.size === 0 && rawSet.size === 0) return qs;
  return qs.filter((q) => {
    if (q.eventYear == null) return true;
    if (played.has(q.eventYear)) return true;
    return isAuthorVerbatimLegendId(q.id) && rawSet.has(q.eventYear);
  });
}

/** Ordered pool for level slicing and flat mode: authored + deduped pad when under 50 questions. */
export const buildPlayerQuestionPool = (playerId: string): Question[] => {
  const playedYears = getPlayerWorldCupYearsSorted(playerId);
  const rawYearsMerged = getMergedRawPlayerWorldCupYearsSorted(playerId);
  const raw = dedupeLegendPlayerQuestions(createPlayerQuestions(playerId));
  const cleaned = stripPlayerQuestionNoise(filterPlayerQuestionsToPlayedWorldCupYears(playerId, raw));
  let focused = filterOffTopicPlayerQuestions(cleaned, playerId);
  const meta = inferPlayerQuizMeta(playerId, focused, {
    allPlayers,
    playerWorldCupYears,
    missingPlayerWorldCupYears,
    effectiveWorldCupYears: playedYears,
  });
  if (meta && focused.length < 50) {
    const extra = buildExtraQuestions(meta, focused);
    focused = dedupeLegendPlayerQuestions([...focused, ...extra]);
    focused = filterOffTopicPlayerQuestions(focused, playerId);
  }
  focused = stripPlayerQuestionNoise(focused);
  focused = limitHostFillersPerPlayer(focused, 0);
  focused = applyMatchLogPolicyToPool(focused, playedYears, rawYearsMerged);
  focused = normalizePlayerPoolToTenGrid(focused, playerId, meta);
  focused = applyMatchLogPolicyToPool(focused, playedYears, rawYearsMerged);
  focused = stripPlayerQuestionNoise(focused);
  return filterPoolForHostBudget(focused);
};

/**
 * Distinct FIFA World Cup finals tournaments this legend actually played in (squad-only years excluded).
 * Used for tiering only — not titles won, not knockout rounds reached.
 */
export const getPlayerWorldCupCount = (playerId: string): number =>
  getPlayerWorldCupYearsSorted(playerId).length;

/**
 * World Cup year for internal level index (1-based), chronological (played years only).
 * If the tier has more levels than recorded finals appearances, returns undefined.
 */
export const getPlayerWorldCupYearForLevel = (playerId: string, level: number): number | undefined => {
  const years = getPlayerWorldCupYearsForLevelsSorted(playerId);
  if (!years.length || level < 1) return undefined;
  const idx = level - 1;
  if (idx >= years.length) return undefined;
  return years[idx];
};

/** Preferred questions per level (large pools); then 30; then 10 for legacy pools. */
export const PLAYER_LEVEL_QTY_PRIMARY = 40;
export const PLAYER_LEVEL_QTY_ALT = 30;
export const PLAYER_LEVEL_QTY_LEGACY = 10;

