export const isAsianLegendPlayer = (playerId: string): boolean =>
  ASIAN_LEGEND_PLAYER_IDS.has(playerId);

/**
 * Max full levels for Select a Legend tiers (capped by World Cup finals count):
 * 1 WC → 1 level of 10; 2 WC → 3; 3+ WC → min(WC count, 5).
 */
export const getPlayerMaxFullLevels = (playerId: string): number => {
  const n = getPlayerWorldCupCount(playerId);
  if (n <= 1) return 1;
  if (n === 2) return 3;
  return Math.min(n, 5);
};

/**
 * Minimum full levels when the pool is large enough: 3 WC → at least 3 levels;
 * 4+ WC → at least 3 levels (three blocks of 10 questions each when the pool is 30).
 */
export const getPlayerMinFullLevels = (playerId: string): number => {
  const n = getPlayerWorldCupCount(playerId);
  if (n <= 2) return 1;
  if (n === 3) return 3;
  return 3;
};

/** @deprecated use getPlayerMaxFullLevels */
export const getPlayerLevelCap = (playerId: string): number => getPlayerMaxFullLevels(playerId);

/**
 * One World Cup tile = one level = exactly 10 questions about that tournament only.
 */
export const getPlayerLevelChunkSize = (_playerId: string): number => PLAYER_LEVEL_QTY_LEGACY;

/** Cumulative question count through completed levels (chunk × level index). */
export const playerLevelToMilestone = (playerId: string, internalLevel: number): number =>
  internalLevel * getPlayerLevelChunkSize(playerId);

/** UI copy: internal level index → "Level 1", "Level 2", … (not 10/20/30). */
export const formatPlayerLevelLabel = (internalLevel: number): string =>
  internalLevel < 1 ? '—' : `Level ${internalLevel}`;

export const getPlayerQuestions = (playerId: string): Question[] => buildPlayerQuestionPool(playerId);

/** Full levels: tier max × pool, but not below tier minimum when the pool supports it. */
export const getPlayerFullLevelCount = (playerId: string): number => {
  const pool = buildPlayerQuestionPool(playerId);
  const poolLen = pool.length;
  const chunk = getPlayerLevelChunkSize(playerId);
  const wcCount = getPlayerWorldCupCount(playerId);
  const compactLegend =
    isAfricanLegendPlayer(playerId) || isAsianLegendPlayer(playerId) || wcCount <= 1;
  const poolLevels =
    poolLen === 0
      ? 0
      : compactLegend
        ? Math.ceil(poolLen / chunk)
        : Math.floor(poolLen / chunk);
  const minL = getPlayerMinFullLevels(playerId);
  const maxL = getPlayerMaxFullLevels(playerId);
  const minRequired = compactLegend ? Math.min(minL, poolLevels) : minL;

  const yearLevels =
    !compactLegend && wcCount >= 2
      ? Math.max(
          countDistinctYearLevelsWithQuestions(playerId, pool),
          countYearsWithEventYearTag(playerId, pool),
        )
      : 0;

  // Multi-year legends: one host-flag tile per World Cup that has at least one stem/year-tagged
  // question, even when floor(pool/chunk) is 1 (e.g. ~10 questions split across 1970 + 1974).
  if (poolLevels < minRequired) {
    if (yearLevels >= 1 && poolLen >= chunk) {
      return Math.min(maxL, yearLevels);
    }
    return 0;
  }

  let levels = Math.min(maxL, poolLevels);
  if (!compactLegend && wcCount >= 2 && yearLevels >= 1) {
    levels = Math.min(maxL, Math.max(levels, yearLevels));
  }
  return levels;
};

/** Usable question count after dedupe and noise filters (not raw file length). */
export const getAuthoredPlayerQuestionCount = (playerId: string): number => {
  return buildPlayerQuestionPool(playerId).length;
};

/** Not enough for tier minimum levels — single pass through all unique questions. */
export const isThinLegendPlayer = (playerId: string): boolean =>
  getPlayerFullLevelCount(playerId) < 1;

/** One run: every unique prompt in order (thin careers). */
export const getPlayerFlatQuizQuestions = (playerId: string): Question[] => {
  const unverifiableStatRe =
    /(shooting accuracy|pass accuracy|distance covered|distance\\b|key passes|successful dribbles|total minutes|playing time|minutes\\b|goals per game ratio)/i;
  const pool = buildPlayerQuestionPool(playerId);
  const preferred = pool.filter(
    (q) => !unverifiableStatRe.test(q.question) && !isCareerAggregateQuestion(q),
  );
  return preferred.length > 0 ? preferred : pool;
};

function extractTournamentYearsFromText(text: string): number[] {
  const years = new Set<number>();
  const re = /\b(19\d{2}|20\d{2})\b/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(text)) !== null) {
    const y = parseInt(m[1], 10);
    if (y >= 1930 && y <= 2038) years.add(y);
  }
  return [...years].sort((a, b) => a - b);
}

function getSortedPlayerWorldCupYears(playerId: string): number[] | undefined {
  const y = getPlayerWorldCupYearsForLevelsSorted(playerId);
  return y.length > 0 ? y : undefined;
}

/**
 * Primary tournament year for level alignment: `eventYear`; else leading "(In|At) the [YEAR] World Cup" on the
 * question (legacy openers before strip); else earliest player-WC year in stem/hints.
 * If the stem omits a year but the **correct** option text contains one (e.g. “which World Cup year”
 * with only years in choices), use that — distractor options are not scanned.
 */
function primaryStemYearForPlayerQuestion(q: Question, playerYears: number[]): number | undefined {
  if (q.eventYear != null && playerYears.includes(q.eventYear)) {
    return q.eventYear;
  }
  const qOnly = q.question.trim();
  const leadingWc = /^(?:In|At) the (19\d{2}|20\d{2}) World Cup\b/i.exec(qOnly);
  if (leadingWc) {
    const y = parseInt(leadingWc[1], 10);
    if (playerYears.includes(y)) return y;
  }
  const stem = [q.question, q.hint1, q.hint2, q.hint3, q.hint4].filter(Boolean).join(' ');
  const inStem = extractTournamentYearsFromText(stem).filter((y) => playerYears.includes(y));
  if (inStem.length > 0) return Math.min(...inStem);

  const stemQ = q.question.trim();
  const looksLikeWhichYear =
    /which (year|world cup|tournament)|in what year|what year did|what year was|in which (year|world cup)/i.test(
      stemQ,
    );
  if (looksLikeWhichYear) {
    const correctOpt =
      q.correctAnswer === 'A'
        ? q.optionA
        : q.correctAnswer === 'B'
          ? q.optionB
          : q.correctAnswer === 'C'
            ? q.optionC
            : q.optionD;
    const inCorrect = extractTournamentYearsFromText(correctOpt ?? '').filter((y) => playerYears.includes(y));
    if (inCorrect.length > 0) return Math.min(...inCorrect);
  }

  return undefined;
}

function listMatchesForTargetYear(
  pool: Question[],
  playerYears: number[],
  targetYear: number,
): Question[] {
  const out: Question[] = [];
  for (const q of pool) {
    if (primaryStemYearForPlayerQuestion(q, playerYears) !== targetYear) continue;
    if (hasContaminatingPlayerWcYear(q, targetYear, playerYears)) continue;
    out.push(q);
  }
  return out;
}

/**
 * Extra bucket filler: text mentions the target year, and the resolved primary year for bucketing
 * is exactly that year (avoids hints like "2014, 2018, 2022" pulling a card into the wrong level).
 */
function listLooseYearMentionQuestions(
  pool: Question[],
  playerYears: number[],
  targetYear: number,
): Question[] {
  if (!playerYears.includes(targetYear)) return [];
  const re = new RegExp(`\\b${targetYear}\\b`);
  const out: Question[] = [];
  for (const q of pool) {
    const blob = [q.question, q.hint1, q.hint2, q.hint3, q.hint4, q.optionA, q.optionB, q.optionC, q.optionD]
      .filter(Boolean)
      .join(' ');
    if (!re.test(blob)) continue;
    if (primaryStemYearForPlayerQuestion(q, playerYears) !== targetYear) continue;
    if (hasContaminatingPlayerWcYear(q, targetYear, playerYears)) continue;
    out.push(q);
  }
  return out;
}

const LEADING_IN_THE_WC_RE = /^(?:In|At) the (19\d{2}|20\d{2}) World Cup\b/i;

/** How many of this legend's World Cup years have at least one question in the pool (legacy leading opener / eventYear tagging, strict bucket, then loose \\byear\\b). */
function countDistinctYearLevelsWithQuestions(playerId: string, pool: Question[]): number {
  const years = getPlayerWorldCupYearsForLevelsSorted(playerId);
  if (years.length === 0) return 0;
  let n = 0;
  for (const y of years) {
    const hasLeadingStem = pool.some((q) => {
      const m = LEADING_IN_THE_WC_RE.exec(q.question.trim());
      return m != null && parseInt(m[1], 10) === y;
    });
    if (hasLeadingStem) {
      n++;
      continue;
    }
    const strict = listMatchesForTargetYear(pool, years, y);
    if (strict.length > 0) {
      n++;
      continue;
    }
    const loose = listLooseYearMentionQuestions(pool, years, y);
    if (loose.length > 0) n++;
  }
  return n;
}

/** Years where at least one pooled question sets `eventYear` (performance batches, Messi-style locks). */
function countYearsWithEventYearTag(playerId: string, pool: Question[]): number {
  const years = getPlayerWorldCupYearsForLevelsSorted(playerId);
  if (!years.length) return 0;
  let n = 0;
  for (const y of years) {
    if (pool.some((q) => q.eventYear === y)) n++;
  }
  return n;
}

/**
 * Year-tagged prompts go to their tournament bucket only (no neutral/career padding between levels).
 */
function buildYearLockedBuckets(
  pool: Question[],
  playerId: string,
  _chunk: number,
  levelCount: number,
): Question[][] {
  const playerYears = getSortedPlayerWorldCupYears(playerId);
  if (!playerYears || playerYears.length === 0) {
    return [];
  }

  const buckets: Question[][] = Array.from({ length: levelCount }, () => []);
  for (let L = 1; L <= levelCount; L++) {
    const y = getPlayerWorldCupYearForLevel(playerId, L);
    if (y === undefined) continue;
    buckets[L - 1] = listMatchesForTargetYear(pool, playerYears, y);
  }

  return buckets;
}

/** Author verbatim tiles (`{player}-av-{year}-··` IDs) ordered after bulk imports — lift them ahead of pooled filler within a tournament bucket. */
const authorVerbatimYearTileId = /^[a-z]+-av-\d{4}-\d/;
function prioritizeAuthorYearVerbatim(picked: Question[], targetYear: number): Question[] {
  const pri = picked.filter(
    (q) => authorVerbatimYearTileId.test(q.id) && q.eventYear === targetYear,
  );
  const seen = new Set(pri.map((q) => q.id));
  return [...pri, ...picked.filter((q) => !seen.has(q.id))];
}

function pickYearLockedPlayerQuestionsForLevel(
  pool: Question[],
  playerId: string,
  level: number,
  chunk: number,
  effectiveMax: number,
): Question[] {
  const playerYears = getSortedPlayerWorldCupYears(playerId);
  if (!playerYears || playerYears.length === 0) {
    const start = (level - 1) * chunk;
    return pool.slice(start, start + chunk);
  }

  const targetYear = getPlayerWorldCupYearForLevel(playerId, level);
  const buckets = buildYearLockedBuckets(pool, playerId, chunk, effectiveMax);
  if (buckets.length === 0 || targetYear === undefined) {
    const start = (level - 1) * chunk;
    return pool.slice(start, start + chunk);
  }

  let picked = prioritizeAuthorYearVerbatim(buckets[level - 1] ?? [], targetYear);
  if (picked.length >= chunk) {
    return picked.slice(0, chunk);
  }

  const strictIds = new Set(picked.map((q) => q.id));
  const loose = listLooseYearMentionQuestions(pool, playerYears, targetYear).filter((q) => !strictIds.has(q.id));
  picked = prioritizeAuthorYearVerbatim([...picked, ...loose], targetYear).slice(0, chunk);

  // Never fall back to a positional slice: pool order mixes tournaments and would show the wrong year on this level.
  return prioritizeAuthorYearVerbatim(picked, targetYear).slice(0, chunk);
}

// Levels 1..N (N = getPlayerFullLevelCount); each level uses getPlayerLevelChunkSize (40, 30, or 10).
export const getPlayerQuestionsByLevel = (playerId: string, level: number): Question[] => {
  const unverifiableStatRe =
    /(shooting accuracy|pass accuracy|distance covered|distance\\b|key passes|successful dribbles|total minutes|playing time|minutes\\b|goals per game ratio)/i;

  let pool = buildPlayerQuestionPool(playerId);
  const preferred = pool.filter(
    (q) => !unverifiableStatRe.test(q.question) && !isCareerAggregateQuestion(q),
  );
  const effectiveMax = getPlayerFullLevelCount(playerId);
  const chunk = getPlayerLevelChunkSize(playerId);
  const wcYears = getPlayerWorldCupYearsSorted(playerId);

  // "Thin" multi-year legends: tier math yields 0 full levels, but each host-flag tile must still
  // load only that tournament (not the flat mixed pool fallback in PlayerGame).
  if (effectiveMax < 1 && wcYears.length > 1) {
    if (level < 1 || level > wcYears.length) {
      return [];
    }
    if (preferred.length >= wcYears.length * chunk) {
      pool = preferred;
    }
    const targetYear = wcYears[level - 1];
    const picked = pickYearLockedPlayerQuestionsForLevel(pool, playerId, level, chunk, wcYears.length);
    const py = getSortedPlayerWorldCupYears(playerId);
    if (!py) return picked;
    return picked.filter((q) => primaryStemYearForPlayerQuestion(q, py) === targetYear);
  }

  if (effectiveMax < 1) {
    return [];
  }
  if (preferred.length >= effectiveMax * chunk) {
    pool = preferred;
  }

  if (level < 1 || level > effectiveMax) {
    return [];
  }

  const targetYear = getPlayerWorldCupYearForLevel(playerId, level);
  if (targetYear === undefined) {
    const start = (level - 1) * chunk;
    return pool.slice(start, start + chunk);
  }

  const picked = pickYearLockedPlayerQuestionsForLevel(pool, playerId, level, chunk, effectiveMax);
  const py = getSortedPlayerWorldCupYears(playerId);
  if (!py) return picked;
  return picked.filter((q) => primaryStemYearForPlayerQuestion(q, py) === targetYear);
};

