const PLAYER_QUESTION_ALIASES: Record<string, string[]> = {
  'javier-hernandez': ['chicharito'],
};

function normText(s: string): string {
  return s.normalize('NFD').replace(/\p{M}/gu, '').toLowerCase();
}

/** Keeps questions tied to this player’s World Cup career; drops generic host/club padding. */
function filterOffTopicPlayerQuestions(questions: Question[], playerId: string): Question[] {
  const p = allPlayers.find((x) => x.id === playerId);
  if (!p) return questions;

  const countryNorm = normText(p.country);
  const nameTokens = p.name
    .split(/[\s']/)
    .map((s) => normText(s))
    .filter((s) => s.length >= 2);
  const aliases = (PLAYER_QUESTION_ALIASES[playerId] ?? []).map((a) => normText(a));

  const questionMentionsPlayerOrTeam = (questionText: string): boolean => {
    const qn = normText(questionText);
    if (qn.includes(countryNorm)) return true;
    for (const a of aliases) {
      if (a.length >= 3 && qn.includes(a)) return true;
    }
    for (const n of nameTokens) {
      if (n.length >= 3 && qn.includes(n)) return true;
      if (n.length === 2 && qn.includes(n)) return true;
    }
    return false;
  };

  return questions.filter((q) => {
    const t = q.question.trim();
    const tl = t.toLowerCase();

    if (/which club did .* join after/i.test(tl)) return false;
    if (/which club did .* (sign|join|move to) after/i.test(tl)) return false;
    if (/after the \d{4} world cup/i.test(tl) && /club|signed|joined|transfer|manchester|real madrid|barcelona|chelsea|bayern/i.test(tl)) {
      return false;
    }

    if (/which country hosted the \d{4}/i.test(tl) && !questionMentionsPlayerOrTeam(t)) return false;
    if (/which country hosted the fifa world cup/i.test(tl) && !questionMentionsPlayerOrTeam(t)) return false;

    if (/\bwho was\b.{0,100}\bhead coach\b/i.test(tl)) return false;

    // Manager / other-person trivia — legend quizzes should centre on the named player's actions.
    if (/\bwho\s+(managed|coached)\b/i.test(tl)) return false;
    if (/\b(head coach|bench boss|national team boss)\b/i.test(tl)) return false;
    if (/\b(managed|coached)\s+.{0,80}\s+(to the|national team|semi-?final|world cup)/i.test(tl)) return false;
    if (/\bşenol\s+güneş|senol\s+gun|fatih\s+terim|bruno\s+metsu\b/i.test(tl)) return false;

    return true;
  });
}
